import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { getProduct, addToCart, addRating } from "../api/api";

function ProductDetail() {

  const { id } = useParams();

  const [product, setProduct] = useState(null);
  const [rating, setRating] = useState(5);

  useEffect(() => {
    loadProduct();
  }, []);

  async function loadProduct() {
    const data = await getProduct(id);
    setProduct(data);
  }

  async function handleAddToCart() {
    await addToCart(1, id, 1);
    alert("Produkten lades i varukorgen");
  }

  async function handleRating() {
    await addRating(id, rating);
    loadProduct();
  }

  if (!product) return <p>Laddar...</p>;

  return (
    <div>

      <h2>{product.product.name}</h2>

<p>{product.product.price} kr</p>

<p>{product.product.description}</p>

{product.product.imageUrl && (
  <img
    src={product.product.imageUrl}
    alt={product.product.name}
    style={{ width: "200px", marginTop: "10px", display: "block" }}
  />
)}

      <button onClick={handleAddToCart}>
        Lägg i varukorg
      </button>

      <h3>Rating</h3>

      <p>
        Snitt: {Number(product.averageRating).toFixed(1)}
      </p>

      <select onChange={e => setRating(e.target.value)}>
        <option value="1">1</option>
        <option value="2">2</option>
        <option value="3">3</option>
        <option value="4">4</option>
        <option value="5">5</option>
      </select>

      <button onClick={handleRating}>
        Skicka rating
      </button>

    </div>
  );
}

export default ProductDetail;
